// src/context.ts
import { privateKeyToAccount as privateKeyToAccount2 } from "viem/accounts";
function createHotstuffContext(config) {
  const httpTransport = new HttpTransport({
    isTestnet: config.isTestnet,
    timeout: config.httpTimeoutMs,
    server: {
      mainnet: {
        api: config.endpoints.mainnet.api,
        rpc: config.endpoints.mainnet.rpc
      },
      testnet: {
        api: config.endpoints.testnet.api,
        rpc: config.endpoints.testnet.rpc
      }
    }
  });
  const wsTransport = new WebSocketTransport({
    isTestnet: config.isTestnet,
    timeout: config.wsTimeoutMs,
    autoConnect: true,
    server: {
      mainnet: config.endpoints.mainnet.ws,
      testnet: config.endpoints.testnet.ws
    }
  });
  const infoTransport = config.useWsReads ? wsTransport : httpTransport;
  const info = new InfoClient({ transport: infoTransport });
  const subscription = new SubscriptionClient({ transport: wsTransport });
  let exchange;
  if (config.privateKey) {
    const wallet = privateKeyToAccount2(config.privateKey);
    exchange = new ExchangeClient({ transport: httpTransport, wallet });
  }
  return {
    config,
    httpTransport,
    wsTransport,
    info,
    subscription,
    exchange
  };
}

// src/instructions.ts
var SERVER_INSTRUCTIONS = `
You are connected to the Hotstuff trading MCP server.

Safety:
- Read-only tools may be used without asking the user each time.
- Every write tool (orders, cancels, leverage, agents, broker approval, referral actions, withdrawals, balance transfers, vault deposit/redeem) requires explicit human confirmation before you call it. Summarize side, size, price, instrument, expiry, and addresses first.
- High-risk actions: cancel_all_orders, withdrawals (request_spot_withdraw, request_derivative_withdraw), external transfers (transfer_spot_balance, transfer_derivative_balance), vault deposit_to_vault and redeem_from_vault \u2014 require extra confirmation.
- If HOTSTUFF_PRIVATE_KEY is not configured, write tools are unavailable; explain that the user must set it in the MCP server environment.

Data:
- For account-scoped reads, omit user to use HOTSTUFF_ACCOUNT_ADDRESS when set.
`.trim();

// src/resources/endpoints.ts
function getEndpointsPayload(isTestnet, endpoints) {
  const urls = getActiveEndpoints(endpoints, isTestnet);
  return {
    network: isTestnet ? "testnet" : "mainnet",
    api: urls.api,
    rpc: urls.rpc,
    ws: urls.ws
  };
}

// src/resources/endpointsResource.ts
function registerEndpointsResource(server2, ctx) {
  server2.registerResource(
    "endpoints",
    "hotstuff://endpoints",
    {
      title: "API endpoints",
      description: "Default HTTP and WebSocket bases for the configured network.",
      mimeType: "application/json"
    },
    async () => ({
      contents: [
        {
          uri: "hotstuff://endpoints",
          mimeType: "application/json",
          text: JSON.stringify(
            {
              fetchedAt: Date.now(),
              isTestnet: ctx.config.isTestnet,
              ...getEndpointsPayload(ctx.config.isTestnet, ctx.config.endpoints)
            },
            null,
            2
          )
        }
      ]
    })
  );
}

