import { z } from "zod";

// src/utils/redact.ts
function redactErrorMessage(message) {
  return message.replace(/\b0x[a-fA-F0-9]{64,}\b/g, "0x[REDACTED]").replace(/\b[a-fA-F0-9]{80,}\b/g, "[REDACTED]");
}

// src/utils/result.ts
function ok(data) {
  return { content: [{ type: "text", text: JSON.stringify(data, null, 2) }] };
}
function toolError(action, error) {
  const raw = error instanceof Error ? error.message : String(error);
  const msg = redactErrorMessage(raw);
  return {
    isError: true,
    content: [{ type: "text", text: `[${action} error] ${msg}` }]
  };
}

// src/utils/user.ts
function resolveUser(ctx, user) {
  const addr = user ?? ctx.config.accountAddress;
  if (!addr) {
    throw new Error("Provide `user` or set HOTSTUFF_ACCOUNT_ADDRESS.");
  }
  return addr;
}
function expiresIn(seconds) {
  return Math.floor(Date.now() / 1e3) + seconds;
}

// src/tools/annotations.ts
var READ_ONLY_ANNOTATION = { readOnlyHint: true };
var DESTRUCTIVE_ANNOTATION = { destructiveHint: true };

