// src/tools/execute/addAgent.ts
import { privateKeyToAccount as privateKeyToAccount3 } from "viem/accounts";
import { z as z14 } from "zod";

// src/utils/requireExchange.ts
function requireExchange(ctx) {
  if (!ctx.exchange) {
    throw new Error(
      "HOTSTUFF_PRIVATE_KEY is required for this action. Set it in the MCP server environment."
    );
  }
  return ctx.exchange;
}

// src/tools/execute/addAgent.ts
function registerAddAgentTool(server2, ctx) {
  server2.registerTool(
    "add_agent",
    {
      title: "Add agent",
      description: "Register a trading agent. Requires HOTSTUFF_PRIVATE_KEY.",
      inputSchema: z14.object({
        agentName: z14.string().min(1),
        agentPrivateKey: z14.string().min(1),
        agent: z14.string().optional(),
        signer: z14.string().optional(),
        forAccount: z14.string().default(""),
        validUntil: z14.number().int().min(0).optional()
      }),
      annotations: DESTRUCTIVE_ANNOTATION
    },
    async ({ agentName, agentPrivateKey, agent, signer, forAccount, validUntil }) => {
      try {
        const ex = requireExchange(ctx);
        const derivedAgent = privateKeyToAccount3(agentPrivateKey).address;
        const resolvedSigner = signer ?? ctx.config.accountAddress;
        if (!resolvedSigner) {
          throw new Error(
            "add_agent requires signer: set HOTSTUFF_ACCOUNT_ADDRESS or pass signer."
          );
        }
        return ok(
          await ex.addAgent({
            agentName,
            agent: agent ?? derivedAgent,
            forAccount,
            agentPrivateKey,
            signer: resolvedSigner,
            validUntil: validUntil ?? expiresIn(30 * 24 * 3600)
          })
        );
      } catch (e) {
        return toolError("add_agent", e);
      }
    }
  );
}

