// src/tools/execute/placeOrder.ts
import { z as z23 } from "zod";

// src/tools/execute/schemas.ts
import { z as z22 } from "zod";
var orderUnitSchema = z22.object({
  instrumentId: z22.number().int().positive(),
  side: z22.enum(["b", "s"]),
  positionSide: z22.enum(["LONG", "SHORT", "BOTH"]),
  price: z22.string().min(1),
  size: z22.string().min(1),
  tif: z22.enum(["GTC", "IOC", "FOK"]),
  ro: z22.boolean(),
  po: z22.boolean(),
  cloid: z22.string().optional(),
  triggerPx: z22.string().optional(),
  isMarket: z22.boolean().optional(),
  tpsl: z22.enum(["", "tp", "sl"]).optional(),
  grouping: z22.enum(["", "position", "normal"]).optional()
});

// src/tools/execute/placeOrder.ts
function registerPlaceOrderTool(server2, ctx) {
  server2.registerTool(
    "place_order",
    {
      title: "Place order",
      description: "Place signed orders. Requires HOTSTUFF_PRIVATE_KEY. Use get_instruments for instrumentId.",
      inputSchema: z23.object({
        orders: z23.array(orderUnitSchema).min(1),
        brokerConfig: z23.object({
          broker: z23.string(),
          fee: z23.string()
        }).optional(),
        expiresAfter: z23.number().int().min(0).optional()
      }),
      annotations: DESTRUCTIVE_ANNOTATION
    },
    async ({ orders, brokerConfig, expiresAfter }) => {
      try {
        const ex = requireExchange(ctx);
        const resolvedOrders = orders.map((o, i) => ({
          ...o,
          cloid: o.cloid ?? `mcp-${Date.now()}-${i}`
        }));
        return ok(
          await ex.placeOrder({
            orders: resolvedOrders,
            brokerConfig: brokerConfig ? { broker: brokerConfig.broker, fee: brokerConfig.fee } : void 0,
            expiresAfter: expiresAfter ?? expiresIn(3600)
          })
        );
      } catch (e) {
        return toolError("place_order", e);
      }
    }
  );
}

