function registerRequestSpotWithdrawTool(server2, ctx) {
  server2.registerTool(
    "request_spot_withdraw",
    {
      title: "Request spot withdraw",
      description: "Spot collateral withdrawal to external chain. Requires HOTSTUFF_PRIVATE_KEY.",
      inputSchema: z26.object({
        collateralId: z26.number().int().positive(),
        amount: z26.string().min(1),
        chainId: z26.number().int().positive()
      }),
      annotations: DESTRUCTIVE_ANNOTATION
    },
    async ({ collateralId, amount, chainId }) => {
      try {
        const ex = requireExchange(ctx);
        return ok(await ex.accountSpotWithdrawRequest({ collateralId, amount, chainId }));
      } catch (e) {
        return toolError("request_spot_withdraw", e);
      }
    }
  );
}

