// src/tools/market/getMidPrices.ts
import { z as z40 } from "zod";
function normalizeSymbol(symbol) {
  if (!symbol) return void 0;
  const normalized = symbol.trim().toUpperCase();
  return normalized.length > 0 ? normalized : void 0;
}
function isRecord(value) {
  return typeof value === "object" && value !== null;
}
function parseMidPrice(value) {
  if (!isRecord(value)) return null;
  if (typeof value.symbol !== "string") return null;
  if (typeof value.mid_price !== "string") return null;
  return {
    symbol: value.symbol,
    mid_price: value.mid_price
  };
}
function pickMidFromResponse(response, requestedSymbol) {
  if (Array.isArray(response)) {
    const mids = response.map(parseMidPrice).filter((item) => item !== null);
    if (mids.length === 0) return null;
    return mids.find((item) => item.symbol.toUpperCase() === requestedSymbol) ?? mids[0];
  }
  return parseMidPrice(response);
}
function hasSymbolRequiredError(error) {
  const message = error instanceof Error ? error.message : String(error);
  return message.toLowerCase().includes("symbol is required");
}
async function getSingleMidPrice(ctx, symbol) {
  try {
    const midsResponse = await ctx.info.mids({ symbol });
    const midFromMids = pickMidFromResponse(midsResponse, symbol);
    if (midFromMids) return midFromMids;
  } catch {
  }
  try {
    const ticker = await ctx.info.ticker({ symbol });
    const first = ticker[0];
    if (first && typeof first.symbol === "string" && typeof first.mid_price === "string") {
      return { symbol: first.symbol, mid_price: first.mid_price };
    }
  } catch {
  }
  return null;
}
async function getAllMidPricesWithFallback(ctx, originalError) {
  const instruments = await ctx.info.instruments({ type: "all" });
  const symbols = Array.from(
    new Set(
      [
        ...instruments.perps.map((instrument) => instrument.name),
        ...instruments.spot.map((instrument) => instrument.name)
      ].map((symbol) => normalizeSymbol(symbol)).filter((symbol) => Boolean(symbol))
    )
  );
  const mids = [];
  for (const symbol of symbols) {
    const mid = await getSingleMidPrice(ctx, symbol);
    if (mid) mids.push(mid);
  }
  if (mids.length === 0) {
    const reason = originalError instanceof Error ? originalError.message : String(originalError);
    throw new Error(`Could not aggregate mid prices after mids() rejected empty input: ${reason}`);
  }
  return mids;
}
function registerGetMidPricesTool(server2, ctx) {
  server2.registerTool(
    "get_mid_prices",
    {
      title: "Get mid prices",
      description: 'Mid prices. Use without params for all symbols; pass `symbol` to fetch one market (e.g. { "symbol": "BTC-PERP" }).',
      inputSchema: z40.object({
        symbol: z40.string().trim().min(1).optional().describe("Optional market symbol, e.g. BTC-PERP.")
      }),
      annotations: READ_ONLY_ANNOTATION
    },
    async ({ symbol }) => {
      try {
        const normalizedSymbol = normalizeSymbol(symbol);
        if (normalizedSymbol) {
          const mid = await getSingleMidPrice(ctx, normalizedSymbol);
          if (!mid) {
            throw new Error(`No mid price found for symbol: ${normalizedSymbol}`);
          }
          return ok([mid]);
        }
        try {
          return ok(await ctx.info.mids({}));
        } catch (e) {
          if (!hasSymbolRequiredError(e)) {
            throw e;
          }
          return ok(await getAllMidPricesWithFallback(ctx, e));
        }
      } catch (e) {
        return toolError("get_mid_prices", e);
      }
    }
  );
}

// src/tools/market/getOraclePrice.ts
import { z as z41 } from "zod";
function buildOracleSymbolCandidates(rawSymbol) {
  const normalized = rawSymbol.trim().toUpperCase();
  if (!normalized.includes("/")) {
    return [normalized, `${normalized}/USDC`];
  }
  return [normalized];
}
function registerGetOraclePriceTool(server2, ctx) {
  server2.registerTool(
    "get_oracle_price",
    {
      title: "Get oracle price",
      description: "Oracle / index price for a symbol. Accepts asset symbols (`BTC`) and pair symbols (`BTC/USDC`).",
      inputSchema: z41.object({
        symbol: z41.string().trim().min(1).describe("Asset or pair symbol, e.g. BTC or BTC/USDC.")
      }),
      annotations: READ_ONLY_ANNOTATION
    },
    async ({ symbol }) => {
      try {
        const candidates = buildOracleSymbolCandidates(symbol);
        let lastError;
        for (const candidate of candidates) {
          try {
            return ok(await ctx.info.oracle({ symbol: candidate }));
          } catch (e) {
            lastError = e;
          }
        }
        const reason = lastError instanceof Error ? lastError.message : String(lastError);
        throw new Error(`${reason}. Tried symbol candidates: ${candidates.join(", ")}`);
      } catch (e) {
        return toolError("get_oracle_price", e);
      }
    }
  );
}

