// src/tools/stream/collectTradesStream.ts
import { z as z46 } from "zod";
var MAX_SECONDS = 120;
var MAX_EVENTS = 2e3;
function registerCollectTradesStreamTool(server2, ctx) {
  server2.registerTool(
    "collect_trades_stream",
    {
      title: "Collect trades stream",
      description: `Subscribe to public trades for an instrument for a bounded time (max ${MAX_SECONDS}s). Pass instrument_id from get_instruments (string).`,
      inputSchema: z46.object({
        instrument_id: z46.string().min(1).describe("Instrument id string from get_instruments."),
        seconds: z46.number().int().min(1).max(MAX_SECONDS).default(10),
        max_events: z46.number().int().min(1).max(MAX_EVENTS).default(300)
      }),
      annotations: READ_ONLY_ANNOTATION
    },
    async ({ instrument_id, seconds, max_events }) => {
      try {
        const events = [];
        const sub = await ctx.subscription.trade(
          { instrumentId: instrument_id },
          (ev) => {
            if (events.length < max_events) {
              events.push(ev.detail);
            }
          }
        );
        await new Promise((r) => setTimeout(r, seconds * 1e3));
        await sub.unsubscribe();
        return ok({
          instrument_id,
          seconds,
          count: events.length,
          events
        });
      } catch (e) {
        return toolError("collect_trades_stream", e);
      }
    }
  );
}

// src/tools/stream/index.ts
function registerStreamTools(server2, ctx) {
  registerCollectTradesStreamTool(server2, ctx);
}

